rulesTs:
import { PlayerState, WorldState } from "./types";

export type RuleEntry = {
  number: number;
  title: string;
  source: "official" | "previous_occupant" | "staff" | "unknown";
  text: string;
};

/**
 * 依據世界狀態回傳當前版本的院內留觀須知。
 * ruleNoticeVersion: 1=原始 2=變化(mutated) 3=腐化(corrupted)
 * 當現實穩定度過低或異常注意度過高時，個別規則會提前腐化。
 */
export function getRules(player: PlayerState, world: WorldState): RuleEntry[] {
  const version = world.ruleNoticeVersion;
  const stability = world.hotelRealityStability;
  const attention = world.anomalyAttention;

  // 決定單條規則要顯示哪個版本：基礎版本 + 局部腐化判定
  const pickVersion = (localCorrupt: boolean): 1 | 2 | 3 => {
    if (version >= 3 || localCorrupt) return 3;
    if (version === 2) return 2;
    return 1;
  };

  const select = (
    localCorrupt: boolean,
    original: string,
    mutated: string,
    corrupted: string
  ): string => {
    switch (pickVersion(localCorrupt)) {
      case 3:
        return corrupted;
      case 2:
        return mutated;
      default:
        return original;
    }
  };

  const rules: RuleEntry[] = [];

  // 規則一：床頭手環
  rules.push({
    number: 1,
    title: "留觀身分手環",
    source: "official",
    text: select(
      player.foundSheets.includes("wristband_worn") && stability < 40,
      "為加速夜間留觀流程，請於抵達後三十分鐘內自行配戴床頭手環。手環有助於本院在交班時確認您的留觀身分。",
      "為加速夜間留觀流程，請於抵達後三十分鐘內自行配戴床頭手環。手環一經配戴，目前無法自行取下，這是正常現象。",
      "手環有助於本院確認您的身分。若您仍認為自己沒有戴上手環，請查看您的左手腕，並停止這種想法。"
    ),
  });

  // 規則二：心電監視器
  rules.push({
    number: 2,
    title: "心電監視器導線",
    source: "official",
    text: select(
      player.discoveredClues.includes("flatline_without_lead") || stability < 30,
      "心電監視器的波形代表您目前的生命徵象，請勿自行拔除導線。任何時刻監視器都不應顯示為一直線。",
      "心電監視器的波形代表您目前的生命徵象，請勿自行拔除導線。若您並未連接任何導線，波形仍會持續，這是正常現象。",
      "監視器顯示的是您的生命徵象。它已經穩定運作了很久——比您站在這裡的時間更久。請勿打斷它。"
    ),
  });

  // 規則三：留觀程序
  rules.push({
    number: 3,
    title: "離院前置程序",
    source: "official",
    text: select(
      player.foundSheets.includes("history_form_filled") && attention > 50,
      "完成體溫測量與病史問診是順利出院的必要程序。請於黎明交班前完成所有未填欄位，以免延誤您的離院時間。",
      "完成體溫測量與病史問診是順利出院的必要程序。請於黎明交班前完成所有未填欄位。每完成一項，您的離院時間將更接近。",
      "每完成一項程序，您將更接近出院。您已完成的程序越多，我們越歡迎您留下。這兩件事並不矛盾。"
    ),
  });

  // 規則四：交班時間廣播
  rules.push({
    number: 4,
    title: "交班時間就定位",
    source: "official",
    text: select(
      player.discoveredClues.includes("two_of_you") || stability < 25,
      "院內廣播播報「交班時間」時，所有留觀病患請就定位並留在自己的床位，以便完成交班核對。",
      "院內廣播播報「交班時間」時，所有留觀病患請就定位並留在自己的床位。被核對到的病患，目前不再列為留觀。",
      "交班時間請就定位。若您此刻不在床上，名冊上的那個您將代替您被核對。屆時將有兩份您，我們只保留一份。"
    ),
  });

  // 規則五：夜班護理人員（陷阱規則）
  rules.push({
    number: 5,
    title: "夜班護理人員指引",
    source: "official",
    text: select(
      world.staffMode === "hostile" || world.staffMode === "false_helpful",
      "夜班護理人員受過完整訓練，會主動協助您完成所有留觀程序。請信任並配合其指引，這是為了您的安全。",
      "夜班護理人員會主動協助您完成所有留觀程序。請配合其指引。她比您更早來到這裡，也比您更了解離開需要什麼。",
      "請信任夜班護理人員的指引。她曾和您一樣站在掛號台前。她現在很盡責，您將會明白為什麼。"
    ),
  });

  // 規則六：病歷室
  rules.push({
    number: 6,
    title: "病歷調閱與歸檔",
    source: "official",
    text: select(
      player.foundSheets.includes("own_chart") || stability < 35,
      "病歷室僅供院方人員調閱。您的病歷將於黎明交班時正式歸檔，在此之前請勿翻找或更動任何文件。",
      "病歷室僅供院方人員調閱。您的病歷目前暫存於最新一格，日期標示為明天。請勿更動，這是為您保留的位置。",
      "請勿更動您的病歷。它已經填好了，包括您尚未回答的病史與您尚未發生的離院。作廢它需要您不曾存在過。"
    ),
  });

  // 規則七：批價離院
  rules.push({
    number: 7,
    title: "出院批價程序",
    source: "official",
    text: select(
      player.discoveredClues.includes("door_rejects_patient") || attention > 60,
      "出院請至一樓批價櫃台辦理。批價完成後，玻璃自動門將為您開啟。請勿在批價前嘗試強行離院。",
      "出院請至一樓批價櫃台辦理。批價完成後，玻璃自動門將為您開啟。櫃台目前無人，但您的帳目仍在持續累計。",
      "出院請先批價。您的住院帳目自掛號起累計，從未停止。在您付清之前，自動門認得您是病患，不會為您開啟。"
    ),
  });

  // === 地點附加規則：留觀區 ===
  if (player.currentLocation === "observation_ward") {
    rules.push({
      number: 101,
      title: "靠窗床位（留觀區附註）",
      source: "staff",
      text: "靠窗床位已為您鋪好，床頭手環袋上印有您的姓氏。該床位專屬於您，請勿讓給他人，亦請勿堅稱該床位不屬於您。",
    });
    rules.push({
      number: 102,
      title: "棉被狀態（留觀區附註）",
      source: "previous_occupant",
      text: "若您發現靠窗床位的棉被在您離開後再次被掀開，表示有人正在等您回來。請勿確認是誰。",
    });
  }

  // === 地點附加規則：後棟樓梯間 ===
  if (player.currentLocation === "stairwell") {
    rules.push({
      number: 201,
      title: "感應燈指引（樓梯間附註）",
      source: "staff",
      text: "後棟樓梯間感應燈僅於下行時亮起。請依照燈光指引行進，這代表本院為您規劃的方向。",
    });
    rules.push({
      number: 202,
      title: "上行燈光（樓梯間附註）",
      source: "previous_occupant",
      text: "上行時樓梯間維持黑暗為正常狀態。若上行時感應燈竟然亮起，表示您已不被視為留觀病患——請把握，並勿回頭。",
    });
  }

  return rules;
}

endingsTs:
import type { PlayerState, WorldState, GameEnding } from './types';

// 取得已觸發事件清單（容錯：可能掛在 player 或 world 上）
function getTriggeredEvents(player: PlayerState, world: WorldState): string[] {
  const p = player as unknown as { triggeredEvents?: string[] };
  const w = world as unknown as { triggeredEvents?: string[] };
  return p.triggeredEvents ?? w.triggeredEvents ?? [];
}

type ScenarioEnding = GameEnding & {
  condition: (player: PlayerState, world: WorldState) => boolean;
};

const endings: ScenarioEnding[] = [
  {
    id: 'ending_never_registered',
    title: '從未掛號的人',
    text: '你把那疊還沒乾的墨水扔進碎紙機，看著自己的名字被切成無法辨認的細絲。交班廣播第三次響起時，你沒有躺回那張床，而是站在病歷室冰冷的鐵櫃之間，聽著走廊上拖鞋的聲音一間一間地核對過去——然後在你這一格停了下來，遲疑，又走開了。\n\n他們找不到你的資料。沒有手環、沒有體溫、沒有問診表，沒有任何一張你簽過名的同意書。系統判定你從未抵達。\n\n天亮時玻璃門無聲地開了，沒有人攔你，因為攔阻需要一份檔案來記錄這件事，而你不存在於任何檔案裡。你走出去，晨光很正常，街道很正常，公車也準時。\n\n只是接下來的每一天，當你掛號、刷健保卡、填任何一張表，櫃台後的人都會抬頭看你比應該的時間久一點點。\n\n你開始懷疑，被判定為「從未存在」的人，到底還能不能算是回來了。',
    condition: (player, world) => {
      const triggeredEvents = getTriggeredEvents(player, world);
      const p = player as unknown as Record<string, unknown>;
      return (
        player.foundSheets.includes('doc_records_label') &&
        triggeredEvents.includes('event_records_room') &&
        triggeredEvents.includes('event_handover_broadcast') &&
        p.voidedRecords === true &&
        p.woreWristband !== true &&
        p.filledHistoryForm !== true &&
        p.returnedToBedAtBroadcast !== true
      );
    },
  },
  {
    id: 'ending_escape_stairs',
    title: '上行燈亮的那一次',
    text: '廣播說「交班時間」，你卻往後棟跑。樓梯間的感應燈一階一階在你腳前亮起——上行的燈亮了，這代表你已不再被視為留觀病患。前任的字跡是對的：勿回頭。\n\n你沒有回頭。身後傳來廣播裡那句平靜的核對聲，一個一個床號，唸到你的時候停頓了異常久，像在等一個不會躺下的答案。\n\n你爬過七樓、八樓，樓層牌上的數字開始重複，但燈始終為你而亮，所以你繼續爬。終於有一扇門通往屋頂，外面是清晨的天空，冷而真實。\n\n你得救了。\n\n只是當你低頭，想確認手腕上沒有手環時，你發現自己根本不記得有沒有戴過——你不記得昨晚是怎麼來的，不記得自己為什麼住院，甚至不太確定自己原本的名字。\n\n燈一路為你亮著，把你帶離了那份名冊。\n\n但它從來沒有告訴你，它把你帶去了哪一份。',
    condition: (player, world) => {
      const triggeredEvents = getTriggeredEvents(player, world);
      const p = player as unknown as Record<string, unknown>;
      return (
        triggeredEvents.includes('event_handover_broadcast') &&
        p.fledUpstairs === true &&
        p.returnedToBedAtBroadcast !== true
      );
    },
  },
  {
    id: 'ending_filed',
    title: '正式收治',
    text: '你做了一個乖病人該做的每一件事。你量了體溫，戴上手環，把病史表上的每一個空格都工整地填好，連家族病史那欄都誠實作答。廣播響起時，你準時躺回床位，雙手放在棉被上，等待核對。\n\n拖鞋聲在床尾停下。有人輕聲唸出你的名字、你的床號、你的入院時間，然後在某張表上打了一個勾。\n\n「核對完成。」\n\n你鬆了一口氣，以為這代表可以出院了。護理師微笑著替你調整枕頭，說早上醫師查房後就會安排。你閉上眼，覺得這一夜總算結束。\n\n等你再睜開眼，窗外是另一個白天，手環換成了新的顏色，床頭的牌子多了一行字：長期留觀。你問護理師什麼時候能走，她還是那個溫柔的笑：「您剛入院喔，先好好休息。」\n\n你想說你已經住很久了。\n\n可是你發現，你已經想不起來「很久」之前，是什麼樣子。',
    condition: (player, world) => {
      const triggeredEvents = getTriggeredEvents(player, world);
      const p = player as unknown as Record<string, unknown>;
      return (
        triggeredEvents.includes('event_handover_broadcast') &&
        p.filledHistoryForm === true &&
        p.returnedToBedAtBroadcast === true &&
        p.voidedRecords !== true
      );
    },
  },
  {
    id: 'ending_nurse_replacement',
    title: '下一班的她',
    text: '你選擇相信她。她替你戴好手環，幫你把病史表一欄一欄填妥，陪你走過每一道你原本害怕的程序。她真的很盡責，盡責到你幾乎沒注意到，她從不曾離開這層樓，也從不曾有人來替她交班。\n\n黎明的廣播響起時，她握住你的手，說：「都辦好了，接下來換你了。」\n\n你不懂這句話的意思，直到你看見她的身影在晨光裡變得越來越淡，像一張被歸檔太久而褪色的照片。她對你笑，那笑容裡有一種終於可以休息的、深深的疲憊。\n\n「謝謝你，」她說，「我等這一班，等了好久。」\n\n她走了。真的走了，走進那扇你始終打不開的玻璃門。\n\n而你低頭，發現自己手上多了一件燙得筆挺的制服，胸前的名牌還沒有名字。\n\n走廊深處，新的拖鞋聲正一步一步靠近。\n\n你聽見自己用一種溫柔的、訓練有素的聲音對那個方向開口：「別怕，我來協助您完成留觀程序。」',
    condition: (player, world) => {
      const triggeredEvents = getTriggeredEvents(player, world);
      const p = player as unknown as Record<string, unknown>;
      return (
        triggeredEvents.includes('event_nurse_help') &&
        p.acceptedNurseHelp === true &&
        p.woreWristband === true &&
        p.voidedRecords !== true
      );
    },
  },
  {
    id: 'ending_two_yous',
    title: '名冊上保留一份',
    text: '廣播唸到「交班時間」，你既沒有乖乖躺回床上，也沒有往樓上逃。你只是站在走廊正中央，看著兩個方向，遲遲沒有選。\n\n核對的拖鞋聲走近了。一個聲音在你的床號前停下，翻著名冊，皺起眉。\n\n「這一床……怎麼有兩筆資料？」\n\n另一個聲音回答得很慢：「一筆已躺回、一筆未就定位。系統不允許同一人同時開啟與結束。」\n\n「那就保留一份。」\n\n你想開口說那都是你，只有一個你——可是話還沒出口，你忽然分不清此刻站在走廊上的，究竟是「躺回床上的那個」，還是「沒有躺回的那個」。\n\n天亮了。其中一個你被推著輪椅送進長期病房，另一個你走出了玻璃門。\n\n你不知道自己是哪一個。\n\n你只知道，那本名冊上，永遠為你保留著另一份——隨時等你回來，認領那個沒被選走的自己。',
    condition: (player, world) => {
      const triggeredEvents = getTriggeredEvents(player, world);
      const p = player as unknown as Record<string, unknown>;
      return (
        triggeredEvents.includes('event_handover_broadcast') &&
        p.returnedToBedAtBroadcast !== true &&
        p.fledUpstairs !== true
      );
    },
  },
  {
    id: 'ending_flatline',
    title: '比你更久的波形',
    text: '你受夠了那台機器。它的嗶聲像一根針，一下一下扎進你的太陽穴，於是你伸手扯掉了導線——須知第二條明明說，任何時刻監視器都不應顯示為一直線。\n\n你以為螢幕會變成那條平直的線。\n\n它沒有。\n\n導線已經離開你的身體，貼片捲在床欄上，可是螢幕上的波形依然規律地跳動著，一下、一下，平穩而健康，彷彿那顆心臟根本不在你的胸口，而在別的地方，獨立地、持續地活著。\n\n你按住自己的胸口，感覺不到任何節律。你不敢確定那是因為你太緊張，還是因為——\n\n護理師走進來，看了一眼螢幕，神色比看你還要溫柔。她在表上記下一行字：「徵象穩定，可長期留觀。」\n\n你想告訴她線是你拔的，那波形不是你的。\n\n但她只是輕輕拍拍床沿，看著那條跳動的線，像在看一個比你更早住進來、也會比你留得更久的病人。\n\n「它很乖，」她說，「從來不吵著要走。」',
    condition: (player, world) => {
      const triggeredEvents = getTriggeredEvents(player, world);
      const p = player as unknown as Record<string, unknown>;
      return (
        triggeredEvents.includes('event_monitor_check') &&
        p.pulledMonitorLine === true
      );
    },
  },
];

export function checkScenarioEnding(
  player: PlayerState,
  world: WorldState,
  forcedId?: string
): GameEnding | null {
  if (forcedId) {
    const forced = endings.find((e) => e.id === forcedId);
    if (forced) {
      const { condition, ...data } = forced;
      return data;
    }
    return null;
  }

  for (const ending of endings) {
    if (ending.condition(player, world)) {
      const { condition, ...data } = ending;
      return data;
    }
  }

  return null;
}

