import type { Dialogue } from "../types";

export const SCENARIO_DIALOGUES: Record<string, Dialogue> = {
  night_nurse_dialogue: {
    id: "night_nurse_dialogue",
    npcName: "夜班護理師（胸牌寫著「林」）",
    startScene: "greet",
    scenes: {
